54→/**
55→ * Soft spring force toward an anchor (galaxy home) position.
56→ * @returns {{ fx: number, fy: number }}
57→ */
58→export function computeAnchorForce(bodyPos, anchorPos, springK) {
59→    const dx = anchorPos.x - bodyPos.x;
60→    const dy = anchorPos.y - bodyPos.y;
61→    return {
62→        fx: dx * springK,
63→        fy: dy * springK,
64→    };
65→}
