67→/**
68→ * Cross-galaxy attraction: pulls a star toward galaxies it has semantic affinity with.
69→ * @param {{ x: number, y: number }} bodyPos
70→ * @param {string} postId
71→ * @param {Map} starPullMap - from buildSemanticMaps
72→ * @param {Map} galaxyPositions - userId → {x,y}
73→ * @param {number} pullK
74→ * @returns {{ fx: number, fy: number }}
75→ */
76→export function computeSemanticPullForce(bodyPos, postId, starPullMap, galaxyPositions, pullK) {
77→    const pulls = starPullMap.get(postId);
78→    if (!pulls || pulls.length === 0) return { fx: 0, fy: 0 };
79→
80→    let fx = 0;
81→    let fy = 0;
82→
83→    for (const { galaxyUserId, similarity } of pulls) {
84→        const galPos = galaxyPositions.get(galaxyUserId);
85→        if (!galPos) continue;
86→
87→        const dx = galPos.x - bodyPos.x;
88→        const dy = galPos.y - bodyPos.y;
89→
90→        // Force scales with similarity
91→        fx += dx * pullK * similarity;
92→        fy += dy * pullK * similarity;
93→    }
94→
95→    return { fx, fy };
96→}
